create table dirkspzm32.lvs_serie_id_kopf (
    sid                   varchar2(2 char) default '01' not null enable,
    firma_nr              number(2, 0) default 1 not null enable,
    serie_id              number(*, 0) not null enable,
    abnr                  varchar2(20 char),
    leitzahl              number(*, 0) not null enable,
    serie_menge           number(*, 0) not null enable,
    serie_start_id        varchar2(50 char) not null enable,
    serie_maske           varchar2(50 char) not null enable,
    serie_extern_maske    varchar2(50 char),
    serie_extern_start_id varchar2(50 char),
    created_date          date not null enable,
    created_login_id      number(*, 0) not null enable,
    last_change_date      date,
    last_change_login_id  number(*, 0),
    serie_gen_richtung    varchar2(2 char) default 'AU'
);

alter table dirkspzm32.lvs_serie_id_kopf
    add constraint chk_serie_gen_richtung
        check ( serie_gen_richtung in ( 'AB', 'AU' ) ) enable;

alter table dirkspzm32.lvs_serie_id_kopf
    add constraint pk_serie_id primary key ( serie_id )
        using index enable;

alter table dirkspzm32.lvs_serie_id_kopf add constraint uk_leitzahl unique ( leitzahl )
    using index enable;


